      return { resultText: response.text, tokenUsage: mapTokenUsage(response, model) };
    };
    return await withRetries(apiCall);
  } catch (error) {
    logFrontendError(error, ErrorSeverity.High, { context: 'analyzeImage Gemini API call' });
    throw error;
  }
};

